-- ----------------------------
-- Table structure for sam_achievement
-- ----------------------------
DROP TABLE IF EXISTS `sam_achievement`;
CREATE TABLE `sam_achievement`  (
  `achievement_id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `session_id` int UNSIGNED NOT NULL COMMENT '届次 id',
  `category` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '类别（字典表 id，政府类/学会类）',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '作品/团队名称',
  `team_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '团队名称',
  `level` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '级别（字典 id）',
  `grade` int NOT NULL COMMENT '获奖等级（字典 id）',
  `track` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '赛道',
  `certificate_no` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '证书编号（唯一）',
  `group_id` int NULL DEFAULT NULL COMMENT '组别（字典 id）',
  `award_time` date NOT NULL COMMENT '获奖时间',
  `year` int NOT NULL COMMENT '年份',
  `owner_dep_id` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '部门',
  `is_reimburse` tinyint(1) NOT NULL COMMENT '是否报销',
  `is_supplement` tinyint(1) NULL DEFAULT NULL COMMENT '是否补录',
  `fee` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '报名费金额',
  `reimbursement_fee` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '实际报销金额',
  `reimbursement_ratio` tinyint UNSIGNED NULL DEFAULT NULL COMMENT '报销百分比（0-100）',
  `reimbursement_item_id` int UNSIGNED NULL DEFAULT NULL COMMENT '报销项目 id',
  `reimbursement_date` datetime NULL DEFAULT NULL COMMENT '报销发放时间',
  `item_index` int NULL DEFAULT NULL COMMENT '报销项目序号',
  `quality_index` int NULL DEFAULT NULL COMMENT '素质提升序号',
  `submitted_at` datetime NULL DEFAULT NULL COMMENT '提交时间',
  `reviewed_at` datetime NULL DEFAULT NULL COMMENT '院级审核时间',
  `school_reviewed_at` datetime NULL DEFAULT NULL COMMENT '校级审核时间',
  `review_result` tinyint NOT NULL DEFAULT 0 COMMENT '院级审核结果（待院级审核0，院级驳回1，院级审核通过2）',
  `schooi_review_result` tinyint NOT NULL DEFAULT 0 COMMENT '校级审核结果（待校级审核2，校级审核通过1，校级驳回0 ）',
  `review_reason` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '院级审核不通过原因',
  `school_review_reason` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '校级审核不通过原因',
  `audit_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '院级审核人',
  `school_audit_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '校级审核人',
  `create_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '创建者',
  `update_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '更新者',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `del_flag` tinyint(1) NOT NULL DEFAULT 0 COMMENT '删除标志（0正常 2删除）',
  `remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '备注',
  PRIMARY KEY (`achievement_id`) USING BTREE,
  UNIQUE INDEX `uk_session_certificate`(`session_id` ASC, `certificate_no` ASC) USING BTREE,
  INDEX `idx_award_time`(`award_time` ASC) USING BTREE,
  INDEX `idx_grade`(`grade` ASC) USING BTREE,
  INDEX `idx_session`(`session_id` ASC) USING BTREE,
  CONSTRAINT `fk_achievement_session` FOREIGN KEY (`session_id`) REFERENCES `sam_competition_session` (`session_id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE = InnoDB AUTO_INCREMENT = 130 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '成果主表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of sam_achievement
-- ----------------------------

-- ----------------------------
-- Table structure for sam_achievement_advisor
-- ----------------------------
DROP TABLE IF EXISTS `sam_achievement_advisor`;
CREATE TABLE `sam_achievement_advisor`  (
  `advisor_id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `achievement_id` int UNSIGNED NOT NULL COMMENT '成果ID',
  `teacher_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `order_no` int NOT NULL COMMENT '排序（1=主指导）',
  `manager` tinyint UNSIGNED NOT NULL DEFAULT 0 COMMENT '是否主要指导',
  `create_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '创建者',
  `update_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '更新者',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `del_flag` tinyint NOT NULL DEFAULT 0,
  `remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL,
  PRIMARY KEY (`advisor_id`) USING BTREE,
  INDEX `idx_achievement`(`achievement_id` ASC) USING BTREE,
  INDEX `idx_teacher_id`(`teacher_id` ASC) USING BTREE,
  CONSTRAINT `fk_advisor_achievement` FOREIGN KEY (`achievement_id`) REFERENCES `sam_achievement` (`achievement_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE = InnoDB AUTO_INCREMENT = 63 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '指导老师' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of sam_achievement_advisor
-- ----------------------------

-- ----------------------------
-- Table structure for sam_achievement_attachment
-- ----------------------------
DROP TABLE IF EXISTS `sam_achievement_attachment`;
CREATE TABLE `sam_achievement_attachment`  (
  `attachment_id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `achievement_id` int UNSIGNED NOT NULL COMMENT '成果ID',
  `type` int NULL DEFAULT NULL COMMENT '附件类型',
  `file_type` int NOT NULL COMMENT '文件类型',
  `create_by` bigint NULL DEFAULT NULL,
  `update_by` bigint NULL DEFAULT NULL,
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `del_flag` tinyint NOT NULL DEFAULT 0,
  `remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL,
  `file_uuid` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '文件UUID（关联sys_file_uuid表）',
  PRIMARY KEY (`attachment_id`) USING BTREE,
  INDEX `fk_attachment_file_uuid`(`file_uuid` ASC) USING BTREE,
  INDEX `idx_achievement`(`achievement_id` ASC) USING BTREE,
  INDEX `idx_type`(`type` ASC) USING BTREE,
  CONSTRAINT `fk_attachment_achievement` FOREIGN KEY (`achievement_id`) REFERENCES `sam_achievement` (`achievement_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_attachment_file_uuid` FOREIGN KEY (`file_uuid`) REFERENCES `sys_file_uuid` (`file_uuid`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 277 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '成果附件' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of sam_achievement_attachment
-- ----------------------------

-- ----------------------------
-- Table structure for sam_achievement_participant
-- ----------------------------
DROP TABLE IF EXISTS `sam_achievement_participant`;
CREATE TABLE `sam_achievement_participant`  (
  `participant_id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `achievement_id` int UNSIGNED NOT NULL COMMENT '成果ID',
  `student_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `order_no` int NOT NULL COMMENT '排序（负责人 1）',
  `manager` tinyint UNSIGNED NOT NULL DEFAULT 0 COMMENT '是否负责人',
  `create_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '创建者',
  `update_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '更新者',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `del_flag` tinyint NOT NULL DEFAULT 0,
  `remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL,
  PRIMARY KEY (`participant_id`) USING BTREE,
  INDEX `idx_achievement`(`achievement_id` ASC) USING BTREE,
  INDEX `idx_student_id`(`student_id` ASC) USING BTREE,
  CONSTRAINT `fk_participant_achievement` FOREIGN KEY (`achievement_id`) REFERENCES `sam_achievement` (`achievement_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE = InnoDB AUTO_INCREMENT = 147 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '参赛选手' ROW_FORMAT = DYNAMIC;

