-- Records of sam_achievement_participant
-- ----------------------------

-- ----------------------------
-- Table structure for sam_competition
-- ----------------------------
DROP TABLE IF EXISTS `sam_competition`;
CREATE TABLE `sam_competition`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `name` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '赛事名称',
  `category` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '类别（政府类/学会类）',
  `organizations` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '盖章单位（多个分号分隔）',
  `level` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '级别（Ⅰ级/Ⅱ级）',
  `tags` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '标签（素质提升表/白名单，多个分号分隔）',
  `memo` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '赛事说明',
  `scope_type` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '适用范围（0=全校，1=指定学院）',
  `status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '状态（0=停用，1=启用）',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '创建人',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '更新人',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '删除标记（0=存在，2=删除）',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 29 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '赛事表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of sam_competition
-- ----------------------------

-- ----------------------------
-- Table structure for sam_competition_apply
-- ----------------------------
DROP TABLE IF EXISTS `sam_competition_apply`;
CREATE TABLE `sam_competition_apply`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `applicant_user_id` bigint NOT NULL COMMENT '申请人用户ID（关联sys_user.user_id）',
  `applicant_dep_id` bigint NOT NULL COMMENT '申请人学院（关联sys_dept.dept_id）',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '赛事名称',
  `session` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '届次（例如2025、十二届）',
  `year` int NULL DEFAULT NULL COMMENT '年份',
  `category` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '类别（政府类/学会类）',
  `organizations` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '盖章单位（多个分号分隔）',
  `tags` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '标签（多个分号分隔）',
  `level` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '比赛级别（I级/II级等）',
  `memo` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '赛事说明',
  `scope_type` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '适用范围（0=全校，1=指定学院）',
  `status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '审核状态（0=待审，1=通过，2=驳回，3=撤回）',
  `audit_by` bigint NULL DEFAULT NULL COMMENT '审核人id（sys_user.user_name/user_id）',
  `audit_time` datetime NULL DEFAULT NULL COMMENT '审核时间',
  `audit_remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '审核意见',
  `competition_id` bigint NULL DEFAULT NULL COMMENT '生成赛事ID（审核通过后关联competition.id）',
  `session_id` bigint NULL DEFAULT NULL COMMENT '生成届次ID（sam_competition_session.session_id）',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '创建人',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '更新人',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '删除标记（0=存在，2=删除）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_applicant_user_id`(`applicant_user_id` ASC) USING BTREE,
  INDEX `idx_applicant_dep_id`(`applicant_dep_id` ASC) USING BTREE,
  INDEX `idx_competition_id`(`competition_id` ASC) USING BTREE,
  INDEX `fk_ca_audit_by`(`audit_by` ASC) USING BTREE,
  CONSTRAINT `fk_ca_applicant_dep_id` FOREIGN KEY (`applicant_dep_id`) REFERENCES `sys_dept` (`dept_id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_ca_audit_by` FOREIGN KEY (`audit_by`) REFERENCES `sys_user` (`user_id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 18 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '赛事申请表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of sam_competition_apply
-- ----------------------------

-- ----------------------------
-- Table structure for sam_competition_apply_attachment
-- ----------------------------
DROP TABLE IF EXISTS `sam_competition_apply_attachment`;
CREATE TABLE `sam_competition_apply_attachment`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `competition_apply_id` bigint NOT NULL COMMENT '关联赛事申请主表主键ID',
  `uuid` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '关联赛事申请主表UUID',
  `document_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '文件原始名称',
  `attachment_type` tinyint NULL DEFAULT NULL COMMENT '附件类型（暂时例如：0=其他，1=赛事方案，2=资质证明）',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '更新者',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '删除标记（0=存在，2=删除）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_attachment_uuid`(`uuid` ASC) USING BTREE,
  INDEX `idx_attachment_apply_id`(`competition_apply_id` ASC) USING BTREE,
  CONSTRAINT `fk_attachment_apply_id` FOREIGN KEY (`competition_apply_id`) REFERENCES `sam_competition_apply` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 48 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '赛事申请附件子表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of sam_competition_apply_attachment
-- ----------------------------

-- ----------------------------
-- Table structure for sam_competition_dept_rel
-- ----------------------------
DROP TABLE IF EXISTS `sam_competition_dept_rel`;
CREATE TABLE `sam_competition_dept_rel`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `session_id` bigint NOT NULL COMMENT '赛事ID（关联competition表主键）',
  `dept_id` bigint NOT NULL COMMENT '学院dept_id（关联sys_dept.dept_id）',
  `sort` int NULL DEFAULT NULL COMMENT '排序',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '创建人',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '更新人',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '删除标记（0=存在，2=删除）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_session_id`(`session_id` ASC) USING BTREE,
  INDEX `idx_dept_id`(`dept_id` ASC) USING BTREE,
  CONSTRAINT `fk_cdr_dept_id` FOREIGN KEY (`dept_id`) REFERENCES `sys_dept` (`dept_id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `fk_cdr_session_id` FOREIGN KEY (`session_id`) REFERENCES `sam_competition` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 9 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '赛事-部门关系表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of sam_competition_dept_rel
-- ----------------------------

-- ----------------------------
-- Table structure for sam_competition_session
-- ----------------------------
DROP TABLE IF EXISTS `sam_competition_session`;
CREATE TABLE `sam_competition_session`  (
  `session_id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `competition_id` bigint NOT NULL COMMENT '赛事ID（关联competition.id）',
  `session` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '届次（例如2025、十九届）',
  `category` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '类别（政府类/学会类）',
  `organizations` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '盖章单位（多个分号分隔）',
  `level` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '级别（Ⅰ级/Ⅱ级）',
  `tags` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '标签（素质提升表/白名单，多个分号分隔）',
  `year` int NULL DEFAULT NULL COMMENT '年份',
  `uuid` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '比赛通知',
  `status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '状态（0=停用，1=启用）',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '创建人',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '更新人',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '删除标记（0=存在，2=删除）',
  PRIMARY KEY (`session_id`) USING BTREE,
  INDEX `idx_competition_id`(`competition_id` ASC) USING BTREE,
  CONSTRAINT `fk_session_competition_id` FOREIGN KEY (`competition_id`) REFERENCES `sam_competition` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 91 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '届次表' ROW_FORMAT = Dynamic;

