  `owner_dep_id` bigint NULL DEFAULT NULL COMMENT '归属学院（sys_dept.dept_id顶层学院）',
  `create_time` datetime NULL DEFAULT NULL COMMENT '生成时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_year`(`year` ASC) USING BTREE,
  INDEX `idx_owner_dep_id`(`owner_dep_id` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '素质提升表' ROW_FORMAT = DYNAMIC;

