-- Records of sam_quality_development_form
-- ----------------------------

-- ----------------------------
-- Table structure for sam_reimbursement_achievement_view
-- ----------------------------
DROP TABLE IF EXISTS `sam_reimbursement_achievement_view`;
CREATE TABLE `sam_reimbursement_achievement_view`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `reimbursement_id` bigint NOT NULL COMMENT '报销项目ID',
  `reimbursement_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '报销项目名称',
  `reimbursement_time` date NULL DEFAULT NULL COMMENT '报销时间',
  `total_fee` decimal(10, 2) NULL DEFAULT NULL COMMENT '总金额',
  `paid_fee` decimal(10, 2) NULL DEFAULT NULL COMMENT '已发放金额',
  `reimbursement_status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '项目状态',
  `achievement_id` int UNSIGNED NOT NULL COMMENT '成果ID',
  `achievement_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '成果名称',
  `team_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '团队名称',
  `level` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '级别',
  `grade` int NULL DEFAULT NULL COMMENT '获奖等级',
  `certificate_no` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '证书编号',
  `fee` decimal(10, 2) NULL DEFAULT NULL COMMENT '报名费',
  `reimbursement_fee` decimal(10, 2) NULL DEFAULT NULL COMMENT '报销金额',
  `award_time` date NULL DEFAULT NULL COMMENT '获奖时间',
  `review_result` tinyint NULL DEFAULT NULL COMMENT '审核结果',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '报销项目关联成果视图表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of sam_reimbursement_achievement_view
-- ----------------------------

-- ----------------------------
-- Table structure for sam_reimbursement_items
-- ----------------------------
DROP TABLE IF EXISTS `sam_reimbursement_items`;
CREATE TABLE `sam_reimbursement_items`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '报销项目名称',
  `reimbursement_time` date NOT NULL COMMENT '报销时间',
  `total_fee` double NOT NULL COMMENT '总金额',
  `paid_fee` double NULL DEFAULT NULL COMMENT '已发放金额',
  `amount` int NULL DEFAULT NULL COMMENT '报销项目数量',
  `owner_dep_id` bigint NOT NULL COMMENT '归属学院（sys_dept.dept_id顶层学院）',
  `status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '状态（0进行中 1已完成）',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '创建人',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '更新人',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '删除标记（0存在 2删除）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_owner_dep_id`(`owner_dep_id` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_reimbursement_time`(`reimbursement_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 9 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '报销项目表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of sam_reimbursement_items
-- ----------------------------

-- ----------------------------
-- Table structure for sam_reimbursement_ratio
-- ----------------------------
DROP TABLE IF EXISTS `sam_reimbursement_ratio`;
CREATE TABLE `sam_reimbursement_ratio`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `grade` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '获奖等级（一等奖、二等奖、三等奖）',
  `category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '类别（政府类、学会类）',
  `ratio` int NULL DEFAULT NULL COMMENT '报销百分比',
  `owner_dep_id` bigint NULL DEFAULT NULL COMMENT '归属学院（sys_dept.dept_id；为空表示全校规则）',
  `status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '1' COMMENT '状态（0停用 1启用）',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '创建人',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '更新人',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '删除标记（0存在 2删除）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_grade`(`grade` ASC) USING BTREE,
  INDEX `idx_category`(`category` ASC) USING BTREE,
  INDEX `idx_owner_dep_id`(`owner_dep_id` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 8 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '报销比例表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of sam_reimbursement_ratio
-- ----------------------------

-- ----------------------------
-- Table structure for sam_student
-- ----------------------------
DROP TABLE IF EXISTS `sam_student`;
CREATE TABLE `sam_student`  (
  `student_id` bigint NOT NULL AUTO_INCREMENT COMMENT '学生id',
  `name` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '学生姓名',
  `no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `school` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '学院',
  `department` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '院系',
  `major` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '专业',
  `class_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '班级',
  `class_year` varchar(11) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '年级',
  PRIMARY KEY (`student_id`) USING BTREE,
  UNIQUE INDEX `no`(`no` ASC) USING BTREE,
  UNIQUE INDEX `no_2`(`no` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 31 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '学生信息表' ROW_FORMAT = DYNAMIC;

