-- ----------------------------
-- Table structure for sam_tag
-- ----------------------------
DROP TABLE IF EXISTS `sam_tag`;
CREATE TABLE `sam_tag`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `competition_session_id` int UNSIGNED NOT NULL COMMENT '届次ID（关联session.id）',
  `tag_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '标签名称（字典/白名单）',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '创建人',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '更新人',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '删除标记（0=存在，2=删除）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_competition_session_id`(`competition_session_id` ASC) USING BTREE,
  CONSTRAINT `fk_tag_session_id` FOREIGN KEY (`competition_session_id`) REFERENCES `sam_competition_session` (`session_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 119 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '标签表' ROW_FORMAT = Dynamic;

